              @click="saveApiBaseUrl"
            >
              Сохранить
            </button>
          </div>
        </div>
        <div class="scanner-toolbar__meta">
          <span class="scanner-pill">Cluster: {{ clusterId || 'local' }}</span>
          <span
            class="scanner-pill"
