          </div>
          <div>
            <dt>Workloads</dt>
            <dd>{{ formatNumber(latestReport.summary.affected_workloads) }}</dd>
          </div>
          <div>
            <dt>Containers</dt>
            <dd>{{ formatNumber(latestReport.summary.affected_containers) }}</dd>
          </div>
        </dl>
        <p v-else>
          Последний отчёт ещё не загружен.
        </p>
      </article>
    </section>

    <section class="scanner-panel">
      <div class="scanner-panel__title scanner-panel__title--between">
        <div>
          <h2>Severity breakdown</h2>
          <p>Ключевые категории уязвимостей по последнему скану.</p>
        </div>
        <div class="scanner-panel__meta">
          {{ formatNumber(totalFindings) }} findings
        </div>
      </div>

      <div
        v-if="severityEntries.length"
        class="scanner-severity"
      >
        <article
          v-for="entry in severityEntries"
          :key="entry[0]"
          class="scanner-severity__item"
          :class="severityCardClass(entry[0])"
        >
          <span>{{ entry[0] }}</span>
          <strong>{{ formatNumber(entry[1]) }}</strong>
          <div class="scanner-meter">
            <div
              class="scanner-meter__fill"
              :style="severityPercentStyle(entry[1])"
            />
          </div>
          <small>{{ severityPercent(entry[1]) }}% от общего объёма</small>
        </article>
      </div>
      <p v-else>
        Нет данных по severity.
      </p>
    </section>

    <section class="scanner-panel">
      <div class="scanner-panel__title scanner-panel__title--between">
        <div>
          <h2>Findings</h2>
          <p>Страница {{ totalPages ? currentPage : 0 }} из {{ totalPages }}. Выбери запись справа для деталей.</p>
        </div>
        <div
          v-if="allItems.length"
          class="scanner-panel__meta"
        >
          Показаны {{ currentRangeStart }}-{{ currentRangeEnd }} из {{ formatNumber(allItems.length) }}
        </div>
      </div>

      <div
        v-if="allItems.length"
        class="scanner-findings"
      >
        <div class="scanner-findings__table-wrap">
          <table class="scanner-table">
            <thead>
              <tr>
                <th>Severity</th>
                <th>Issue</th>
                <th>Namespace</th>
                <th>Workload</th>
                <th>Container</th>
                <th>Title</th>
              </tr>
            </thead>
            <tbody>
              <tr
                v-for="entry in pagedItems"
                :key="entry.key"
                :class="{ 'is-selected': entry.index === selectedFindingIndex }"
                @click="selectFinding(entry.index)"
              >
                <td>
                  <div class="scanner-cell scanner-cell--compact">
                    <span
                      class="scanner-badge"
                      :class="severityBadgeClass(entry.item.severity)"
                    >
                      {{ entry.item.severity || 'unknown' }}
                    </span>
                  </div>
                </td>
                <td>
                  <div class="scanner-cell scanner-cell--compact">
                    <strong class="scanner-table__mono">{{ entry.item.issue_id || 'unknown' }}</strong>
                    <span>{{ issueLabel(entry.item) }}</span>
                  </div>
                </td>
                <td>
                  <div class="scanner-cell scanner-cell--compact">
                    <strong>{{ entry.item.namespace || 'cluster-scoped' }}</strong>
                    <span>{{ namespaceHint(entry.item) }}</span>
                  </div>
                </td>
                <td>
                  <div class="scanner-cell">
                    <strong>{{ resourceLabel(entry.item) }}</strong>
                    <span>{{ workloadHint(entry.item) }}</span>
                  </div>
                </td>
                <td>
                  <div class="scanner-cell scanner-cell--compact">
                    <strong>{{ entry.item.container_name || 'resource' }}</strong>
                    <span class="scanner-table__mono">{{ entry.item.image || 'image unavailable' }}</span>
                  </div>
                </td>
                <td>
                  <div class="scanner-cell">
                    <strong>{{ entry.item.title || 'Без названия' }}</strong>
                    <span>{{ excerpt(entry.item.description || entry.item.remediation || 'Нет дополнительного описания.', 120) }}</span>
                  </div>
                </td>
              </tr>
            </tbody>
          </table>
        </div>

        <aside
          v-if="selectedFinding"
          class="scanner-detail"
        >
          <div class="scanner-detail__header">
            <span
              class="scanner-badge"
              :class="severityBadgeClass(selectedFinding.severity)"
            >
              {{ selectedFinding.severity || 'unknown' }}
            </span>
            <span class="scanner-detail__issue">{{ selectedFinding.issue_id || 'unknown issue' }}</span>
          </div>

          <h3>{{ selectedFinding.title || 'Без названия' }}</h3>

          <dl class="scanner-detail__grid">
            <div>
              <dt>Namespace</dt>
              <dd>{{ selectedFinding.namespace || 'cluster-scoped' }}</dd>
            </div>
            <div>
              <dt>Workload</dt>
              <dd>{{ resourceLabel(selectedFinding) }}</dd>
            </div>
            <div>
              <dt>Container</dt>
              <dd>{{ selectedFinding.container_name || 'resource' }}</dd>
            </div>
            <div>
              <dt>Image</dt>
              <dd class="scanner-kv__mono">{{ selectedFinding.image || 'n/a' }}</dd>
            </div>
          </dl>

          <div
            v-if="selectedFinding.description"
            class="scanner-detail__block"
          >
            <h4>Описание</h4>
            <p>{{ selectedFinding.description }}</p>
          </div>

          <div
            v-if="selectedFinding.remediation"
            class="scanner-detail__block"
          >
            <h4>Рекомендация</h4>
            <p>{{ selectedFinding.remediation }}</p>
          </div>
        </aside>
      </div>

      <div
        v-if="totalPages > 1"
        class="scanner-pagination"
      >
        <div class="scanner-pagination__group">
          <button
            class="scanner-pagination__nav"
            :disabled="currentPage === 1"
            @click="setPage(currentPage - 1)"
          >
            Назад
          </button>
        </div>

        <div class="scanner-pagination__pages">
          <template
            v-for="page in pageButtons"
          >
            <span
              v-if="page.type !== 'page'"
              :key="page.key"
              class="scanner-page-button scanner-page-button--ellipsis"
            >
              {{ page.label }}
            </span>
            <button
              v-else
              :key="page.key"
              class="scanner-page-button"
              :class="{ 'is-active': page.value === currentPage }"
              @click="setPage(page.value)"
            >
              {{ page.label }}
            </button>
          </template>
        </div>

        <div class="scanner-pagination__group scanner-pagination__group--end">
          <button
            class="scanner-pagination__nav"
            :disabled="currentPage === totalPages"
            @click="setPage(currentPage + 1)"
          >
            Вперёд
          </button>
        </div>
      </div>

      <p v-else-if="!loading">
        Findings пока нет.
      </p>
    </section>
  </div>
