<script>
import {
  fetchLatestReport,
  fetchStatus,
  fetchStorageInfo,
  getApiBaseUrl,
  setApiBaseUrl,
  triggerScan,
} from '../api/scanner';

const PAGE_SIZE = 12;
const SEVERITY_ORDER = ['critical', 'high', 'medium', 'low', 'negligible', 'unknown'];

export default {
  name: 'K8sScannerOverviewPage',

  data() {
    return {
      apiBaseUrlInput: '',
      currentPage: 1,
      error: '',
      latestReport: null,
      loading: false,
      scanSubmitting: false,
      selectedFindingIndex: null,
      status: null,
      storageInfo: null,
    };
  },

  computed: {
    clusterId() {
      return this.$route.params.cluster;
    },

    allItems() {
      return this.latestReport?.items || [];
    },

    totalFindings() {
      return this.latestReport?.summary?.total_findings || this.status?.last_scan_findings_count || this.allItems.length;
    },

    totalPages() {
      if (!this.allItems.length) {
        return 0;
      }

      return Math.ceil(this.allItems.length / PAGE_SIZE);
    },

    pagedItems() {
      const start = (this.currentPage - 1) * PAGE_SIZE;

      return this.allItems.slice(start, start + PAGE_SIZE).map((item, offset) => ({
        item,
        index: start + offset,
        key: this.findingKey(item, start + offset),
      }));
    },

    currentRangeStart() {
      if (!this.allItems.length) {
        return 0;
      }

      return (this.currentPage - 1) * PAGE_SIZE + 1;
    },

    currentRangeEnd() {
      if (!this.allItems.length) {
        return 0;
      }

      return Math.min(this.currentPage * PAGE_SIZE, this.allItems.length);
    },

    selectedFinding() {
      if (this.selectedFindingIndex == null) {
        return null;
      }

      return this.allItems[this.selectedFindingIndex] || null;
    },

    severityEntries() {
      const severityCounts = this.latestReport?.summary?.severity_counts || {};

      return Object.entries(severityCounts).sort((left, right) => {
        const leftIndex = SEVERITY_ORDER.indexOf(left[0]);
        const rightIndex = SEVERITY_ORDER.indexOf(right[0]);
        const normalizedLeftIndex = leftIndex === -1 ? SEVERITY_ORDER.length : leftIndex;
        const normalizedRightIndex = rightIndex === -1 ? SEVERITY_ORDER.length : rightIndex;

        return normalizedLeftIndex - normalizedRightIndex;
      });
    },

    pageButtons() {
      if (!this.totalPages) {
        return [];
      }

      const pages = new Set([1, this.totalPages, this.currentPage, this.currentPage - 1, this.currentPage + 1]);
      const normalizedPages = [...pages]
        .filter((page) => page >= 1 && page <= this.totalPages)
        .sort((left, right) => left - right);

      const buttons = [];

      normalizedPages.forEach((page, index) => {
        if (index > 0 && page - normalizedPages[index - 1] > 1) {
          buttons.push({
            key: `ellipsis-${ normalizedPages[index - 1] }-${ page }`,
            label: '…',
            type: 'ellipsis',
          });
        }

        buttons.push({
          key: `page-${ page }`,
          label: page,
          type: 'page',
          value: page,
        });
      });

      return buttons;
    },

    statusLabel() {
      if (this.scanSubmitting || this.status?.scan_in_progress) {
        return 'Scan running';
      }

      return this.status?.last_scan_status ? `Last scan: ${ this.status.last_scan_status }` : 'Scanner idle';
    },

    statusPillClass() {
      if (this.scanSubmitting || this.status?.scan_in_progress) {
        return 'scanner-pill--info';
      }

      if (this.status?.last_scan_status === 'success') {
        return 'scanner-pill--success';
      }

      if (this.status?.last_scan_status === 'failed') {
        return 'scanner-pill--danger';
      }

      return '';
    },

    servicePillClass() {
      if (this.status?.service_status === 'ok') {
        return 'scanner-pill--success';
      }

      return 'scanner-pill--danger';
    },
  },

  created() {
    this.apiBaseUrlInput = getApiBaseUrl(this.clusterId);
    this.refresh();
  },

  methods: {
    formatDate(value) {
      if (!value) {
        return 'n/a';
      }

      return new Date(value).toLocaleString();
    },

    shortDate(value) {
      if (!value) {
        return 'n/a';
      }

      return new Date(value).toLocaleString([], {
        dateStyle: 'medium',
        timeStyle: 'short',
      });
    },

    formatNumber(value) {
      return new Intl.NumberFormat().format(Number(value || 0));
    },

    formatDuration(value) {
      if (value == null) {
        return 'n/a';
      }

      return `${ Math.round(value) }s`;
    },

    findingKey(item, index) {
      return [
        item.namespace || 'cluster',
        item.workload_kind || 'kind',
        item.workload_name || 'name',
        item.container_name || 'container',
        item.issue_id || 'issue',
        item.title || 'title',
        index,
      ].join(':');
    },

    resourceLabel(item) {
      return `${ item.workload_kind || 'resource' }/${ item.workload_name || 'unknown' }`;
    },

    severityBadgeClass(severity) {
      return `scanner-badge--${ (severity || 'unknown').toLowerCase() }`;
    },

    severityCardClass(severity) {
      return `scanner-severity__item--${ (severity || 'unknown').toLowerCase() }`;
    },

    severityPercent(value) {
      if (!this.totalFindings) {
        return '0.0';
      }

      return ((Number(value || 0) / this.totalFindings) * 100).toFixed(1);
    },

    severityPercentStyle(value) {
      return {
        width: `${ Math.max(Number(this.severityPercent(value)), 6) }%`,
      };
    },

    issueLabel(item) {
      return item.title || 'control';
    },

    namespaceHint(item) {
      return item.namespace ? 'namespace scoped' : 'cluster level resource';
    },

    workloadHint(item) {
      if (item.container_name) {
        return item.container_name;
      }

      return item.image || 'resource level finding';
    },

    excerpt(value, limit = 140) {
      const text = (value || '').trim();

      if (!text) {
        return '';
      }

      if (text.length <= limit) {
        return text;
      }

      return `${ text.slice(0, limit - 1).trimEnd() }…`;
    },

    selectFinding(index) {
      this.selectedFindingIndex = index;
    },

    setPage(page) {
      if (page < 1 || page > this.totalPages || page === this.currentPage) {
        return;
      }

      this.currentPage = page;
      this.selectFirstFindingOnPage();
    },

    selectFirstFindingOnPage() {
      if (!this.allItems.length) {
        this.selectedFindingIndex = null;
        return;
      }

      const start = (this.currentPage - 1) * PAGE_SIZE;
      const end = start + PAGE_SIZE;

      if (
        this.selectedFindingIndex == null
        || this.selectedFindingIndex < start
        || this.selectedFindingIndex >= end
        || !this.allItems[this.selectedFindingIndex]
      ) {
        this.selectedFindingIndex = start;
      }
    },

    syncFindingState() {
      if (!this.allItems.length) {
        this.currentPage = 1;
        this.selectedFindingIndex = null;
        return;
      }

      if (this.currentPage > this.totalPages) {
        this.currentPage = this.totalPages;
      }

      this.selectFirstFindingOnPage();
    },

    async refresh() {
      this.loading = true;
      this.error = '';

      try {
        const [status, latestReport, storageInfo] = await Promise.all([
          fetchStatus(this.clusterId),
          fetchLatestReport(this.clusterId),
          fetchStorageInfo(this.clusterId),
        ]);

        this.status = status;
        this.latestReport = latestReport;
        this.storageInfo = storageInfo;
        this.syncFindingState();
      } catch (err) {
        this.error = err instanceof Error ? err.message : String(err);
      } finally {
        this.loading = false;
      }
    },

    saveApiBaseUrl() {
      this.apiBaseUrlInput = setApiBaseUrl(this.apiBaseUrlInput, this.clusterId);
      this.refresh();
    },

    async runScan() {
      this.scanSubmitting = true;
      this.error = '';

      try {
        await triggerScan(this.clusterId);
        await this.refresh();
      } catch (err) {
        this.error = err instanceof Error ? err.message : String(err);
      } finally {
        this.scanSubmitting = false;
      }
    },
  },
};
</script>

