            class="scanner-detail__block"
          >
            <h4>Severity</h4>
            <div class="scanner-chips">
              <span
                v-for="entry in severityEntries"
                :key="entry[0]"
                class="scanner-chip"
              >
                {{ entry[0] }}: {{ formatNumber(entry[1]) }}
              </span>
            </div>
          </div>

