<script>
import { fetchHistory } from '../api/scanner';

const SEVERITY_ORDER = ['critical', 'high', 'medium', 'low', 'negligible', 'unknown'];

export default {
  name: 'K8sScannerHistoryPage',

  data() {
    return {
      error: '',
      history: [],
      loading: false,
      selectedRunId: null,
    };
  },

  computed: {
    clusterId() {
      return this.$route.params.cluster;
    },

    selectedRun() {
      return this.history.find((entry) => entry.run_id === this.selectedRunId) || null;
    },

    successCount() {
      return this.history.filter((entry) => entry.status === 'success').length;
    },

    failedCount() {
      return this.history.filter((entry) => entry.status === 'failed').length;
    },

    severityEntries() {
      const counts = this.selectedRun?.summary?.severity_counts || {};

      return Object.entries(counts).sort((left, right) => {
        const leftIndex = SEVERITY_ORDER.indexOf(left[0]);
        const rightIndex = SEVERITY_ORDER.indexOf(right[0]);
        const normalizedLeftIndex = leftIndex === -1 ? SEVERITY_ORDER.length : leftIndex;
        const normalizedRightIndex = rightIndex === -1 ? SEVERITY_ORDER.length : rightIndex;

        return normalizedLeftIndex - normalizedRightIndex;
      });
    },
  },

  created() {
    this.refresh();
  },

  methods: {
    formatDate(value) {
      if (!value) {
        return 'n/a';
      }

      return new Date(value).toLocaleString();
    },

    shortDate(value) {
      if (!value) {
        return 'n/a';
      }

      return new Date(value).toLocaleString([], {
        dateStyle: 'medium',
        timeStyle: 'short',
      });
    },

    formatNumber(value) {
      return new Intl.NumberFormat().format(Number(value || 0));
    },

    formatDuration(value) {
      if (value == null) {
        return 'n/a';
      }

      return `${ Math.round(value) }s`;
    },

    statusBadgeClass(status) {
      return status === 'success' ? 'scanner-badge--success' : 'scanner-badge--danger';
    },

    selectRun(runId) {
      this.selectedRunId = runId;
    },

    syncSelection() {
      if (!this.history.length) {
        this.selectedRunId = null;
        return;
      }

      if (!this.selectedRunId || !this.history.find((entry) => entry.run_id === this.selectedRunId)) {
        this.selectedRunId = this.history[0].run_id;
      }
    },

    async refresh() {
      this.loading = true;
      this.error = '';

      try {
        this.history = await fetchHistory(50, this.clusterId);
        this.syncSelection();
      } catch (err) {
        this.error = err instanceof Error ? err.message : String(err);
      } finally {
        this.loading = false;
      }
    },
  },
};
</script>

